{
  "name": "dialit",
  "version": "1.0.0",
  "description": "TypeScript conversational flow engine for versioned chatbot definitions.",
  "license": "MIT",
  "type": "module",
  "main": "./dist/index.js",
  "module": "./dist/index.js",
  "types": "./dist/index.d.ts",
  "repository": {
    "type": "git",
    "url": "git+https://github.com/PailletJuanPablo/dialit.git"
  },
  "bugs": {
    "url": "https://github.com/PailletJuanPablo/dialit/issues"
  },
  "homepage": "https://dialit.netlify.app/",
  "exports": {
    ".": {
      "types": "./dist/index.d.ts",
      "import": "./dist/index.js"
    },
    "./runtime-support": {
      "types": "./dist/runtime-support.d.ts",
      "import": "./dist/runtime-support.js"
    },
    "./package.json": "./package.json"
  },
  "sideEffects": false,
  "engines": {
    "node": ">=20"
  },
  "keywords": [
    "chatbot",
    "conversation",
    "workflow",
    "typescript",
    "llm"
  ],
  "files": [
    "dist",
    "README.md",
    "LICENSE"
  ],
  "scripts": {
    "build": "tsc -p tsconfig.json",
    "typecheck:tests": "tsc -p tsconfig.test.json",
    "test": "vitest run",
    "test:package": "node scripts/package-smoke-test.mjs",
    "pack:dry-run": "npm pack --dry-run",
    "prepack": "npm run build",
    "site:dev": "npm --prefix site run dev -- --port 5173",
    "site:build": "npm --prefix site run build",
    "site:preview": "npm --prefix site run preview -- --port 4173"
  },
  "devDependencies": {
    "@types/node": "^20.14.12",
    "typescript": "^5.5.4",
    "vitest": "^2.0.5"
  }
}
